import{_ as a,o,c as r,ag as t}from"./chunks/framework.CfGxNWra.js";const b=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md","lastUpdated":1780485959000}'),d={name:"changelog.md"};function l(i,e,n,s,c,h){return o(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>All notable changes to this project will be documented in this file.</p><p>The format is based on <a href="https://keepachangelog.com/en/1.1.0/" target="_blank" rel="noreferrer">Keep a Changelog</a>, and this project adheres to <a href="https://semver.org/spec/v2.0.0.html" target="_blank" rel="noreferrer">Semantic Versioning</a>.</p><h2 id="unreleased" tabindex="-1"><a href="https://github.com/rodgco/wabox/compare/v0.1.9...HEAD" target="_blank" rel="noreferrer">Unreleased</a> <a class="header-anchor" href="#unreleased" aria-label="Permalink to &quot;[Unreleased]&quot;">​</a></h2><h2 id="_0-1-9-2026-06-04" tabindex="-1"><a href="https://github.com/rodgco/wabox/compare/v0.1.8...v0.1.9" target="_blank" rel="noreferrer">0.1.9</a> - 2026-06-04 <a class="header-anchor" href="#_0-1-9-2026-06-04" aria-label="Permalink to &quot;[0.1.9] - 2026-06-04&quot;">​</a></h2><h2 id="_0-1-8-2026-06-03" tabindex="-1"><a href="https://github.com/rodgco/wabox/compare/v0.1.7...v0.1.8" target="_blank" rel="noreferrer">0.1.8</a> - 2026-06-03 <a class="header-anchor" href="#_0-1-8-2026-06-03" aria-label="Permalink to &quot;[0.1.8] - 2026-06-03&quot;">​</a></h2><h3 id="added" tabindex="-1">Added <a class="header-anchor" href="#added" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Installable agent skill at <code>skills/wabox</code> (Agent Skills / skills.sh standard): <code>npx skills add rodgco/wabox</code> teaches a consumer agent the inbox/outbox contract and the read → remove → respond workflow.</li><li><code>INTEGRATION.md</code> — a guide for agents that consume the boxes (message/job formats, replies, reactions, content types, WhatsApp text formatting, the read-receipt lifecycle, and ready-to-use job examples). Shipped in the npm package.</li></ul><h2 id="_0-1-7-2026-06-03" tabindex="-1"><a href="https://github.com/rodgco/wabox/compare/v0.1.6...v0.1.7" target="_blank" rel="noreferrer">0.1.7</a> - 2026-06-03 <a class="header-anchor" href="#_0-1-7-2026-06-03" aria-label="Permalink to &quot;[0.1.7] - 2026-06-03&quot;">​</a></h2><h3 id="fixed" tabindex="-1">Fixed <a class="header-anchor" href="#fixed" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><code>wabox update</code> could reinstall the version you already had because npm&#39;s cached <code>@latest</code> dist-tag was stale. It now resolves the concrete latest version with a fresh registry read and installs with <code>--prefer-online</code>.</li></ul><h2 id="_0-1-6-2026-06-03" tabindex="-1"><a href="https://github.com/rodgco/wabox/compare/v0.1.5...v0.1.6" target="_blank" rel="noreferrer">0.1.6</a> - 2026-06-03 <a class="header-anchor" href="#_0-1-6-2026-06-03" aria-label="Permalink to &quot;[0.1.6] - 2026-06-03&quot;">​</a></h2><h3 id="fixed-1" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-1" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Allow list now matches the sender&#39;s real phone number even when the chat is routed via a LID (<code>@lid</code>): it checks <code>senderPn</code>/<code>participantPn</code>, not just the chat JID. Previously messages from an allowed number could be wrongly rejected.</li></ul><h3 id="added-1" tabindex="-1">Added <a class="header-anchor" href="#added-1" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Inbox records now include the sender&#39;s resolved <code>number</code>, and the rejection log shows the real phone number (not the LID).</li></ul><h2 id="_0-1-5-2026-06-03" tabindex="-1"><a href="https://github.com/rodgco/wabox/compare/v0.1.4...v0.1.5" target="_blank" rel="noreferrer">0.1.5</a> - 2026-06-03 <a class="header-anchor" href="#_0-1-5-2026-06-03" aria-label="Permalink to &quot;[0.1.5] - 2026-06-03&quot;">​</a></h2><h3 id="added-2" tabindex="-1">Added <a class="header-anchor" href="#added-2" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Log rejected senders (phone number + name) at <code>info</code> level when the allow list blocks a message, so you can see who tried to reach a restricted inbox.</li></ul><h2 id="_0-1-4-2026-06-03" tabindex="-1"><a href="https://github.com/rodgco/wabox/compare/v0.1.3...v0.1.4" target="_blank" rel="noreferrer">0.1.4</a> - 2026-06-03 <a class="header-anchor" href="#_0-1-4-2026-06-03" aria-label="Permalink to &quot;[0.1.4] - 2026-06-03&quot;">​</a></h2><h3 id="added-3" tabindex="-1">Added <a class="header-anchor" href="#added-3" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><code>wabox allow</code> command — manage who can reach the inbox by phone number (<code>list</code>/<code>add</code>/<code>remove</code>/<code>clear</code>), edited offline in <code>config.json</code> with the service restarted automatically.</li></ul><h2 id="_0-1-3-2026-06-03" tabindex="-1"><a href="https://github.com/rodgco/wabox/compare/v0.1.1...v0.1.3" target="_blank" rel="noreferrer">0.1.3</a> - 2026-06-03 <a class="header-anchor" href="#_0-1-3-2026-06-03" aria-label="Permalink to &quot;[0.1.3] - 2026-06-03&quot;">​</a></h2><h3 id="added-4" tabindex="-1">Added <a class="header-anchor" href="#added-4" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Send a native WhatsApp read receipt (blue checkmarks) when a message&#39;s <code>.json</code> is removed from the inbox. The consumer owns inbox cleanup; deleting a file is the &quot;message processed&quot; signal.</li><li><code>wabox update</code> command — updates the global npm package and restarts the background service.</li></ul><h3 id="changed" tabindex="-1">Changed <a class="header-anchor" href="#changed" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>Quiet Baileys&#39; chatty internal logs by giving it its own logger (default <code>warn</code>, tunable via <code>BAILEYS_LOG_LEVEL</code>), so harmless app-state resync and init-query timeouts no longer flood the journal.</li></ul><blockquote><p>Note: version 0.1.2 was bumped during development but never published to npm; its logging change shipped as part of 0.1.3.</p></blockquote><h2 id="_0-1-1-2026-06-03" tabindex="-1"><a href="https://github.com/rodgco/wabox/compare/v0.1.0...v0.1.1" target="_blank" rel="noreferrer">0.1.1</a> - 2026-06-03 <a class="header-anchor" href="#_0-1-1-2026-06-03" aria-label="Permalink to &quot;[0.1.1] - 2026-06-03&quot;">​</a></h2><h3 id="fixed-2" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-2" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Complete WhatsApp pairing reliably: reconnect on stream error 515 (&quot;restart required&quot;), which WhatsApp sends right after the QR scan. Pairing previously stopped at this point and appeared to fail.</li></ul><h2 id="_0-1-0-2026-06-03" tabindex="-1"><a href="https://github.com/rodgco/wabox/releases/tag/v0.1.0" target="_blank" rel="noreferrer">0.1.0</a> - 2026-06-03 <a class="header-anchor" href="#_0-1-0-2026-06-03" aria-label="Permalink to &quot;[0.1.0] - 2026-06-03&quot;">​</a></h2><p>Initial release.</p><h3 id="added-5" tabindex="-1">Added <a class="header-anchor" href="#added-5" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>WhatsApp ↔ filesystem bridge built on <a href="https://github.com/WhiskeySockets/Baileys" target="_blank" rel="noreferrer">Baileys</a>: QR pairing with a persisted session and automatic reconnect.</li><li>Incoming messages (text + media) saved to an <code>inbox/</code> folder as JSON, with media downloaded alongside.</li><li>Outbox folder watched for outgoing jobs — send text, files, quoted replies, and emoji reactions.</li><li>Cross-platform CLI (<code>config</code>, <code>run</code>, <code>pair</code>, <code>status</code>, <code>uninstall</code>) with an interactive setup, native per-OS paths (XDG on Linux, Application Support on macOS, <code>%APPDATA%</code>/<code>%LOCALAPPDATA%</code> on Windows), and background-service install via systemd, launchd, or Windows Task Scheduler.</li><li>MIT license and contribution guidelines, including an AI-assistance policy.</li></ul>',35)])])}const g=a(d,[["render",l]]);export{b as __pageData,g as default};
